import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  Palette,
  Building,
  ShoppingBag,
  Megaphone,
  Star,
  TrendingUp,
  Crown,
} from "lucide-react";
import {
  signUpWithEmail,
  loginWithEmail,
  signInWithGoogle,
  logout,
  monitorAuthState,
} from "../firebase";
import Footer from "../components/Footer";

function Home() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLogin, setIsLogin] = useState(true);
  const [user, setUser] = useState(null);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  // 🔁 Keep user logged in
  useEffect(() => {
    monitorAuthState((currentUser) => setUser(currentUser));
  }, []);

  // 🧠 Handle Auth Submit
  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg("");
    setLoading(true);
    try {
      if (isLogin) {
        await loginWithEmail(email, password);
      } else {
        await signUpWithEmail(email, password);
      }
      setIsModalOpen(false);
      setEmail("");
      setPassword("");
    } catch (err) {
      setErrorMsg(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignIn = async () => {
    try {
      await signInWithGoogle();
      setIsModalOpen(false);
    } catch (err) {
      setErrorMsg(err.message);
    }
  };

  const handleLogout = async () => {
    await logout();
  };

  return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-gray-900 text-gray-900 dark:text-gray-200">
      <main className="flex-grow">
        {/* Hero Section */}
        <section className="relative min-h-screen flex flex-col justify-center items-center text-center bg-gradient-to-br from-black via-gray-800 to-gray-900 text-white overflow-hidden px-6 md:px-20">
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold mb-6"
            initial={{ opacity: 0, y: 50 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            The Grand Coordinating Enterprise
          </motion.h1>
          <motion.p
            className="text-lg md:text-xl mb-8 max-w-2xl"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.3 }}
          >
            Where creativity meets commerce, and vision shapes reality.
          </motion.p>

          {/* Buttons */}
          <div className="flex flex-col md:flex-row justify-center gap-4">
            <Link to="/about">
              <motion.button
                className="px-6 py-3 bg-yellow-500 text-black font-semibold rounded-lg shadow hover:bg-yellow-600 transition"
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                Explore Our Empire
              </motion.button>
            </Link>

            {user ? (
              <button
                onClick={handleLogout}
                className="px-6 py-3 border border-yellow-500 text-yellow-500 font-semibold rounded-lg hover:bg-yellow-500 hover:text-black transition"
              >
                Logout ({user.email})
              </button>
            ) : (
              <button
                onClick={() => setIsModalOpen(true)}
                className="px-6 py-3 border border-yellow-500 text-yellow-500 font-semibold rounded-lg hover:bg-yellow-500 hover:text-black transition"
              >
                Sign Up / Login
              </button>
            )}
          </div>
        </section>

        {/* About Section */}
        <section className="py-16 text-center px-6 md:px-20">
          <h2 className="text-2xl md:text-3xl font-bold mb-6">About Us</h2>
          <p className="max-w-3xl mx-auto text-base md:text-lg text-gray-600 dark:text-gray-300">
            We are a multidimensional powerhouse uniting graphic design, fashion design, real estate,
            architecture, trade, marketing and commercials into one grand tapestry. Godemar’s Empire is not just a brand — it is a legacy in motion.
          </p>
        </section>

        {/* Domains */}
        <section className="py-20 px-6 md:px-20 bg-gray-100 dark:bg-gray-800">
          <h2 className="text-2xl md:text-3xl font-bold text-center mb-12">Our Core Domains</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {[
              { icon: Palette, title: "Graphic & Fashion Design", text: "Bold visuals and garments that speak culture and identity." },
              { icon: Building, title: "Real Estate & Architecture", text: "Structures that inspire. Spaces that last." },
              { icon: ShoppingBag, title: "Trade & Commerce", text: "Connecting markets and opportunities globally." },
              { icon: Megaphone, title: "Marketing & Commercials", text: "Turning messages into unforgettable movements." },
            ].map((item, i) => (
              <article key={i} className="p-6 bg-white dark:bg-gray-900 rounded-xl shadow-lg text-center hover:-translate-y-2 transition-transform">
                <item.icon size={40} className="mx-auto text-yellow-500 mb-4" />
                <h3 className="font-bold text-lg mb-2">{item.title}</h3>
                <p className="text-gray-600 dark:text-gray-400">{item.text}</p>
              </article>
            ))}
          </div>
        </section>
      </main>

      <Footer />

      {/* Signup/Login Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div
            className="fixed inset-0 bg-black bg-opacity-60 flex justify-center items-center z-50"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <motion.div
              className="bg-white dark:bg-gray-900 rounded-xl w-full max-w-md p-6 relative"
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.8, opacity: 0 }}
              transition={{ duration: 0.3 }}
            >
              <button
                className="absolute top-3 right-3 text-gray-500 hover:text-yellow-500"
                onClick={() => setIsModalOpen(false)}
              >
                ✕
              </button>

              {/* Tabs */}
              <div className="flex justify-center mb-4">
                {["Login", "Signup"].map((tab, i) => (
                  <button
                    key={i}
                    onClick={() => setIsLogin(tab === "Login")}
                    className={`px-4 py-2 font-semibold rounded-t-lg ${
                      isLogin === (tab === "Login")
                        ? "bg-yellow-500 text-black"
                        : "bg-gray-200 dark:bg-gray-800 text-gray-700 dark:text-gray-300"
                    }`}
                  >
                    {tab}
                  </button>
                ))}
              </div>

              <form onSubmit={handleSubmit} className="flex flex-col gap-4 mt-4">
                {!isLogin && (
                  <input
                    type="text"
                    placeholder="Full Name"
                    className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-700 focus:ring-2 focus:ring-yellow-500"
                  />
                )}
                <input
                  type="email"
                  placeholder="Email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-700 focus:ring-2 focus:ring-yellow-500"
                />
                <input
                  type="password"
                  placeholder="Password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-700 focus:ring-2 focus:ring-yellow-500"
                />
                {errorMsg && (
                  <p className="text-red-500 text-sm text-center">{errorMsg}</p>
                )}
                <button
                  type="submit"
                  disabled={loading}
                  className="px-4 py-2 bg-yellow-500 text-black font-semibold rounded-lg hover:bg-yellow-600 transition disabled:opacity-50"
                >
                  {loading ? "Processing..." : isLogin ? "Login" : "Signup"}
                </button>
              </form>

              <div className="flex items-center my-4">
                <hr className="flex-grow border-gray-300 dark:border-gray-700" />
                <span className="px-2 text-gray-500 dark:text-gray-400 text-sm">OR</span>
                <hr className="flex-grow border-gray-300 dark:border-gray-700" />
              </div>

              <button
                onClick={handleGoogleSignIn}
                className="w-full flex items-center justify-center gap-2 px-4 py-2 border border-gray-300 dark:border-gray-700 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-800 transition font-semibold"
              >
                <img
                  src="https://upload.wikimedia.org/wikipedia/commons/5/53/Google_%22G%22_Logo.svg"
                  alt="Google"
                  className="w-5 h-5"
                />
                {isLogin ? "Login with Google" : "Signup with Google"}
              </button>

              <p className="text-sm text-gray-500 dark:text-gray-400 mt-4 text-center">
